arguments.file_text:
@page "/apply"
@rendermode InteractiveServer
@using sv_7120f5ac859f486b9dadbb6d86a52ee9.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h1 class="mb-4">Job Application</h1>

    @if (submitted)
    {
        <div class="alert alert-success text-center py-5">
            <h2 class="mb-3">✅ Application Submitted!</h2>
            <p class="lead">Your application ID is <strong>#@applicationId</strong></p>
            <p>We'll be in touch soon. Thank you for applying!</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="currentStep"
                       CompletedSteps="completedSteps"
                       OnStepClicked="GoToStep" />

        <div class="card mt-4">
            <div class="card-body">
                @switch (currentStep)
                {
                    case 1:
                        <PersonalInfoStep FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                                          FullNameChanged="v => fullName = v"
                                          EmailChanged="v => email = v"
                                          PhoneChanged="v => phone = v"
                                          AddressChanged="v => address = v"
                                          OnNext="HandlePersonalNext"
                                          ValidationError="@validationError" />
                        break;
                    case 2:
                        <WorkHistoryStep Entries="workEntries"
                                         OnBack="() => GoToStep(1)"
                                         OnNext="HandleWorkNext" />
                        break;
                    case 3:
                        <ReferencesStep References="references"
                                        OnBack="() => GoToStep(2)"
                                        OnNext="HandleReferencesNext" />
                        break;
                    case 4:
                        <CoverLetterStep @bind-CoverLetter="coverLetter"
                                         OnBack="() => GoToStep(3)"
                                         OnNext="HandleCoverLetterNext" />
                        break;
                    case 5:
                        <ReviewStep FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                                    WorkEntries="workEntries" References="references" CoverLetter="@coverLetter"
                                    OnEdit="GoToStep"
                                    OnSubmit="HandleSubmit"
                                    IsSubmitting="isSubmitting" />
                        break;
                }
            </div>
        </div>
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();

    private string fullName = "";
    private string email = "";
    private string phone = "";
    private string address = "";
    private string coverLetter = "";
    private string? validationError;

    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };

    private bool submitted;
    private int applicationId;
    private bool isSubmitting;

    private async Task HandlePersonalNext()
    {
        validationError = null;

        if (string.IsNullOrWhiteSpace(fullName) || string.IsNullOrWhiteSpace(email)
            || string.IsNullOrWhiteSpace(phone) || string.IsNullOrWhiteSpace(address))
        {
            validationError = "All fields are required.";
            return;
        }

        var emailValid = await ApplicationService.ValidateEmailAsync(email);
        if (!emailValid)
        {
            validationError = "Please enter a valid email address.";
            return;
        }

        completedSteps.Add(1);
        currentStep = 2;
    }

    private void HandleWorkNext()
    {
        completedSteps.Add(2);
        currentStep = 3;
    }

    private void HandleReferencesNext()
    {
        completedSteps.Add(3);
        currentStep = 4;
    }

    private void HandleCoverLetterNext()
    {
        completedSteps.Add(4);
        currentStep = 5;
    }

    private void GoToStep(int step)
    {
        if (step < currentStep || completedSteps.Contains(step))
        {
            currentStep = step;
        }
    }

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        StateHasChanged();

        var personal = new PersonalInfo(fullName, email, phone, address);
        var work = new WorkHistory(workEntries.Select(e =>
            new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList());
        var refs = references
            .Where(r => !string.IsNullOrWhiteSpace(r.Name))
            .Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
        var app = new JobApplication(personal, work, refs, coverLetter);

        applicationId = await ApplicationService.SubmitApplicationAsync(app);
        submitted = true;
        isSubmitting = false;
    }

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; } = DateTime.Today;
        public DateTime? EndDate { get; set; } = DateTime.Today;
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    public class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}

@using static sv_7120f5ac859f486b9dadbb6d86a52ee9.Components.Pages.Apply.Apply

<h4 class="card-title mb-3">References</h4>
<p class="text-muted">Please provide 2–3 professional references.</p>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var reference = References[index];

    <div class="border rounded p-3 mb-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <h6 class="mb-0">Reference @(index + 1)</h6>
            @if (References.Count > 2)
            {
                <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveReference(index)">Remove</button>
            }
        </div>

