                }
                else
                {
                    <span>@step</span>
                }
            </button>
            <div class="small mt-1 @(isCurrent ? "fw-bold" : isCompleted ? "" : "text-muted")">
                @stepNames[step - 1]
            </div>
        </div>

        @if (step < stepNames.Length)
        {
            <div class="flex-fill align-self-start" style="margin-top: 16px;">
                <hr class="@(CompletedSteps.Contains(step) ? "border-primary" : "border-secondary opacity-25")" />
            </div>
        }
    }
