    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    private string StepBadgeClass(int step)
    {
        if (step == CurrentStep) return "btn-primary";
        if (CompletedSteps.Contains(step)) return "btn-success";
        return "btn-outline-secondary";
    }
