@using static sv_7120f5ac859f486b9dadbb6d86a52ee9.Components.Pages.Apply.Apply

<h4 class="card-title mb-3">References</h4>
<p class="text-muted">Please provide 2–3 professional references.</p>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var reference = References[index];

    <div class="border rounded p-3 mb-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <h6 class="mb-0">Reference @(index + 1)</h6>
            @if (References.Count > 2)
            {
                <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveReference(index)">Remove</button>
            }
        </div>

        <div class="row mb-2">
            <div class="col-md-6">
                <label class="form-label">Name</label>
                <input class="form-control" @bind="reference.Name" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship</label>
                <input class="form-control" @bind="reference.Relationship" />
            </div>
        </div>
        <div class="row mb-2">
            <div class="col-md-6">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="reference.Email" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone</label>
                <input type="tel" class="form-control" @bind="reference.Phone" />
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next →</button>
</div>

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddReference() => References.Add(new ReferenceModel());

    private void RemoveReference(int index) => References.RemoveAt(index);
}

@using static sv_7120f5ac859f486b9dadbb6d86a52ee9.Components.Pages.Apply.Apply

<h4 class="card-title mb-4">Review Your Application</h4>

<!-- Personal Info -->
<div class="mb-4">
    <div class="d-flex justify-content-between align-items-center">
        <h5>Personal Information</h5>
        <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
    </div>
    <dl class="row mb-0">
        <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@FullName</dd>
        <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Email</dd>
        <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Phone</dd>
        <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Address</dd>
    </dl>
</div>

<hr />

<!-- Work History -->
<div class="mb-4">
    <div class="d-flex justify-content-between align-items-center">
        <h5>Work History</h5>
        <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
    </div>
    @foreach (var entry in WorkEntries)
    {
        <div class="mb-2 ps-2 border-start border-3 border-primary">
            <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
            <small class="text-muted">
                @entry.StartDate.ToString("MMM yyyy") –
                @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
            </small>
            @if (!string.IsNullOrWhiteSpace(entry.Description))
            {
                <p class="mb-0 mt-1">@entry.Description</p>
            }
        </div>
    }
</div>

<hr />

<!-- References -->
<div class="mb-4">
    <div class="d-flex justify-content-between align-items-center">
        <h5>References</h5>
        <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
    </div>
    @foreach (var r in References.Where(r => !string.IsNullOrWhiteSpace(r.Name)))
    {
        <div class="mb-2">
            <strong>@r.Name</strong> — @r.Relationship<br />
            <small class="text-muted">@r.Email · @r.Phone</small>
        </div>
    }
</div>

<hr />

<!-- Cover Letter -->
<div class="mb-4">
    <div class="d-flex justify-content-between align-items-center">
        <h5>Cover Letter</h5>
        <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(4)">Edit</button>
    </div>
    <div class="bg-light p-3 rounded" style="white-space: pre-wrap;">@CoverLetter</div>
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
        @if (IsSubmitting)
        {
            <span class="spinner-border spinner-border-sm me-2" role="status"></span>
            <span>Submitting…</span>
        }
        else
        {
            <span>Submit Application</span>
        }
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public bool IsSubmitting { get; set; }
}

